<template>
  <div id="app">
    <navbar/>
    <transition name="trans-router">
      <router-view/>
    </transition>
    <v-footer/>
  </div>
</template>

<script>
import Navbar from './components/ui/Navbar'
import VFooter from './components/ui/VFooter'

export default {
  name: 'App',
  components: {
    Navbar,
    VFooter
  },
  methods: {
    setTitle (metaTitle) {
      const titleSuffix = 'Holmes Web Development'
      document.title = metaTitle ? metaTitle + ' | ' + titleSuffix : titleSuffix
    }
  },
  watch: {
    $route (to, from) {
      this.setTitle(to.meta.title)
      document.getElementsByTagName('meta')['description'].content = to.meta.description
      window.scrollTo(0, 0)
    }
  },
  beforeMount () {
    this.setTitle(this.$route.meta.title)
  }
}
</script>



