<template>
  <div class="hero flex">
    <div class="hero-text flex align-center">
      <div>
        <transition name="fadeInUp">
          <h1 v-if="showText" ref="heading1">Make an Impact <span class="c-primary">Online</span></h1>
        </transition>
        <transition name="fadeInUp">
          <h3 v-if="showText" class="fw-light ff-secondary trans-delay-350">We make beautiful websites for beautiful businesses.</h3>
        </transition>
        <transition name="fadeInUp">
          <router-link v-if="showText" to="/contact" class="button call-to-action fw-regular bc-primary c-white bc-hover-white border-hover-primary c-hover-primary trans-delay-700">Get Online</router-link>
        </transition>
      </div>
    </div>
    <div class="hero-img img-container">
      <picture>
        <source
          srcset="../../assets/images/hero-desktop.png"
          media="(min-width: 992px)"
        >
        <source
          srcset="../../assets/images/hero-tablet.png"
          media="(min-width: 768px) and (max-width: 991.98px)"
        >
        <img src="../../assets/images/hero-mobile.png" alt="Holmes Web Development">
      </picture>
    </div>
  </div>
</template>

<script>
export default {
  name: 'Hero',
  data () {
    return {
      showText: false
    }
  },
  mounted () {
    this.showText = true
  }
}
</script>



