import Vue from 'vue'
import Router from 'vue-router'
import Index from '@/components/views/Index'
import Services from '@/components/views/Services'
import Contact from '@/components/views/Contact'
import Terms from '@/components/views/Terms'

Vue.use(Router)

export default new Router({
  mode: 'history',
  routes: [
    {
      path: '/',
      name: 'Home',
      component: Index,
      meta: {
        title: 'Welcome',
        description: 'Holmes Web Development: web design, web development, SEO, digital marketing and more.',
        nav: true
      }
    },
    {
      path: '/services',
      name: 'Services',
      component: Services,
      meta: {
        title: 'Web Development Services',
        description: 'Web development services by Holmes Web Development.',
        nav: true
      }
    },
    {
      path: '/contact',
      name: 'Contact',
      component: Contact,
      meta: {
        title: 'Contact Us',
        description: 'Contact Holmes Web Development.',
        nav: true
      }
    },
    {
      path: '/terms',
      name: 'Terms of Service',
      component: Terms,
      meta: {
        title: 'Terms of Service',
        description: 'Holmes Web Development terms of service.'
      }
    }
  ]
})



