<template>
  <footer
    class="footer bc-secondary"
    :class="'footer-' + pathLowerCase"
  >
    <div class="container flex justify-between">
      <img src="../../assets/images/signature.svg" alt="Holmes Web Development">
      <div class="footer-nav text-align-right">
        <router-link
        v-for="(route, i) in $navRoutes"
        :key="i"
        :to="route.path"
        class="footer-nav-item"
        >
          {{ route.name }}
        </router-link>
        <router-link
        to="/terms"
        class="footer-nav-item"
        >
          Terms of Service
        </router-link>
      </div>
    </div>
  </footer>
</template>

<script>
export default {
  name: 'VFooter',
  computed: {
    pathLowerCase () {
      return this.$route.name.toLowerCase()
    }
  }
}
</script>

<style>

</style>



