<template>
  <nav
    class="navbar"
    :class="{ 'navbar-home': isHome }"
  >
    <div class="navbar-heading">
      <router-link to="/">
        <img class="svg-icon" src="../../assets/images/signature.svg" alt="Holmes Web Development">
      </router-link>
    </div>
    <div
      class="navbar-nav c-text-primary flex"
      :class="{ 'shown': navShown }"
    >
      <div
        @click="closeNav"
        class="navbar-nav-close text-align-right"
      >
      <icon class="svg-icon">
        <icon-close/>
      </icon>
      </div>
      <router-link
        v-for="(route, i) in $navRoutes"
        :key="i"
        :to="route.path"
        class="nav-link"
        @click.native="closeNav"
      >
        {{ route.name }}
      </router-link>
    </div>
    <div
      @click="showNav"
      class="navbar-nav-toggle"
    >
      <icon class="svg-icon">
        <icon-menu/>
      </icon>
    </div>
  </nav>
</template>

<script>
import IconMenu from '@/components/icons/IconMenu'
import IconClose from '@/components/icons/IconClose'

export default {
  name: 'Navbar',
  components: {
    IconMenu,
    IconClose
  },
  data () {
    return {
      navShown: false
    }
  },
  computed: {
    isHome () {
      return this.$route.path === '/'
    }
  },
  methods: {
    showNav () {
      this.navShown = true
    },
    closeNav () {
      this.navShown = false
    }
  },
  beforeMount () {
    window.addEventListener(
      'resize',
      () => {
        if (window.innerWidth >= 768) {
          this.closeNav()
        }
      }
    )
  }
}
</script>



