// Content block with an icon, heading and content
<template>
  <div class="content-block">
    <h3>
      <icon class="svg-icon">
        <slot name="icon"/>
      </icon>
      <slot name="heading"/>
    </h3>
    <div>
      <slot name="content"/>
    </div>
  </div>
</template>

<script>
export default {
  name: 'ContentBlock'
}
</script>



